def add_header(key, value, headers=None):
    if headers is None:
        headers = {}
    headers[key] = value
    return headers

h1 = add_header('Content-Type', 'application/json')
h1 = add_header('Authorization', 'Bearer abc', h1)

h2 = add_header('Accept', 'text/html')

print(h1)
print(h2)

